    public static long solve(long[][] grid) {
        int m = grid.length;
        int n = grid[0].length;
        int maxK = 10;

        // Priority queue for Dijkstra's algorithm
        PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(a[0], b[0]));
        pq.offer(new long[]{0, 0, 0}); // cost, row, col, remainingK

        // Distance array: distance[i][j][k] represents the minimum cost to reach (i, j) with k remaining teleports
        long[][][] dist = new long[m][n][maxK + 1];

        // Initialize distance array with infinity
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                for (int k = 0; k <= maxK; k++) {
                    dist[i][j][k] = Long.MAX_VALUE;
                }
            }
        }

        // Starting point
        dist[0][0][maxK] = 0;

        while (!pq.isEmpty()) {
            long[] current = pq.poll();
            long cost = current[0];
            int row = current[1];
            int col = current[2];
            int remainingK = (int) current[3];

            // If we have reached the destination, return the cost
            if (row == m - 1 && col == n - 1) {
                return cost;
            }

            // Regular move: right or down
            if (col + 1 < n) {
                long newCost = cost + grid[row][col + 1];
                if (newCost < dist[row][col + 1][remainingK]) {
                    dist[row][col + 1][remainingK] = newCost;
                    pq.offer(new long[]{newCost, row, col + 1, remainingK});
                }
            }
            if (row + 1 < m) {
                long newCost = cost + grid[row][col + 1];
                if (newCost < dist[row + 1][col][remainingK]) {
                    dist[row + 1][col][remainingK] = newCost;
                    pq.offer(new long[]{newCost, row + 1, col, remainingK});
                }
            }

            // Teleport move: find all cells with value <= current cell's value
            for (int i = 0; i < m; i++) {
                for (int j = 0; j < n; j++) {
                    if (grid[i][j] <= grid[row][col] && remainingK > 0) {
                        if (cost < dist[i][j][remainingK - 1]) {
                            dist[i][j][remainingK - 1] = cost;
                            pq.offer(new long[]{cost, i, j, remainingK - 1});
                        }
                    }
                }
            }
        }

        // If we can't reach the destination, return -1 (though the problem says it's always possible)
        return -1;
    }
