    pq.offer(new long[]{0, 0, 0}); // cost, row, col

    // dp[i][j][k] represents the minimum cost to reach (i, j) with k uses of teleport
    long[][][] dp = new long[m][n][k + 1];
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            for (int t = 0; t <= k; t++) {
                dp[i][j][t] = Long.MAX_VALUE;
            }
        }
    }
    dp[0][0][0] = 0;

    int[] dx = {0, 1};
