        int x = pq.peek()[1];
        int y = pq.peek()[2];
        pq.poll();

        if (x == m - 1 && y == n - 1) {
            return cost;
        }

        // Regular move: right or down
        for (int i = 0; i < 2; i++) {
            int nx = x + dx[i];
            int ny = y + dy[i];
            if (nx < m && ny < n) {
                long newCost = cost + grid[nx][ny];
                if (newCost < dp[nx][ny][0]) {
                    dp[nx][ny][0] = newCost;
                    pq.offer(new long[]{newCost, nx, ny});
                }
            }
        }

        // Teleport: find all cells with value <= current cell's value
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                if (grid[i][j] <= grid[x][y] && dp[i][j][0] > cost) {
                    dp[i][j][0] = cost;
                    pq.offer(new long[]{cost, i, j});
                }
            }
        }
    }

    return dp[m - 1][n - 1][0];
}
